command:
/**
 * Macro that puts a request for a skill check into the chat.
 * Gets the list of available skills, and opens a dialog asking for
 * the details of the roll.
 *
 * Allows failure and success messages to be set as well. After that,
 * a chat message is sent to all players which they can click on to
 * make the check for their character.
 *
 * Demonstrates how to use dialogs and make skill checks from a macro.
 */
const SKILLS = CONFIG.MGT2.getDefaultSkills();
const fields = foundry.applications.fields;

let skillOptions = [];
let skillLabels = {};
for (let id in SKILLS) {
  let skill = SKILLS[id];
  skillLabels[id] = game.i18n.localize("MGT2.Skills." + id);
  skillOptions.push({
    label: game.i18n.localize("MGT2.Skills." + id),
    value: id
  });
  if (skill.specialities) {
    for (let spec in skill.specialities) {
      skillLabels[id+"."+spec] = `${game.i18n.localize("MGT2.Skills." + id)} (${game.i18n.localize("MGT2.Skills." + spec)})`;
      skillOptions.push({
        label: `${game.i18n.localize("MGT2.Skills." + id)} (${game.i18n.localize("MGT2.Skills." + spec)})`,
        value: id + "." + spec
      });
    }
  }
}

const skillInput = fields.createSelectInput({
  name: "skill",
  options: skillOptions
});
const difficultyInput = fields.createNumberInput({
  name: 'difficulty',
  value: 8
});
const characteristicInput = fields.createSelectInput({
  name: "characteristic",
  options: [
    { label: "STR", value: "STR" },
    { label: "DEX", value: "DEX" },
    { label: "END", value: "END" },
    { label: "INT", value: "INT" },
    { label: "EDU", value: "EDU" },
    { label: "SOC", value: "SOC" },
  ],
  value: "INT"
});
const titleInput = fields.createTextInput({
  name: 'description',
  value: "Make a skill roll"
});
const successInput = fields.createTextInput({
  name: 'success',
  value: "Success"
});
const failInput = fields.createTextInput({
  name: 'failure',
  value: "Failure"
});


const content = `
<div class="grid grid-3col">
<div><label>Select skill</label>${skillInput.outerHTML}</div>
<div><label>Difficulty</label>${difficultyInput.outerHTML}</div>
<div><label>Characteristic</label>${characteristicInput.outerHTML}</div>
</div>
<div><label>Roll Text</label>${titleInput.outerHTML}</div>
<div><label>Success Text</label>${successInput.outerHTML}</div>
<div><label>Failure Text</label>${failInput.outerHTML}</div>
`;

const data = await foundry.applications.api.DialogV2.input({
  window: { title: "Request skill check" },
  content: content,
  ok: {
    label: "Roll!"
  }
});

/*
 * If you just want to make a simple skill roll, rather than request a roll,
 * then use this commented out code rather than what follows.
game.mgt2e.rollSkillMacro(data.skill, {
  difficulty: data.difficulty,
  cha: data.characteristic
});
*/

let jsonData = {
    skill: data.skill,
    "dm": 0,
    "rollType": "standard",
    "difficulty": data.difficulty,
    "cha": data.characteristic,
    "description": data.description,
    "success": data.success,
    "failure": data.failure
};

let icon = data.skill.replaceAll(/\..*/g, "");
let contentData = {
  skillIcon: `systems/mgt2e/icons/skills/${icon}.svg`,
  skillTitle: skillLabels[data.skill],
  skillFqn: data.skill,
  json: JSON.stringify(jsonData),
  difficulty: data.difficulty,
  description: data.description
};

const c = await foundry.applications.handlebars.renderTemplate("systems/mgt2e/templates/chat/skill-request.html", contentData);
let chatData = {
    content: c,
    rollMode: game.settings.get("core", "rollMode")
}
ChatMessage.create(chatData, {});
